-- 463: S58 group — dedup M3 G80/G81 split engine + moat-fill the 8 S58 gens:
-- M3 G80 142 + G80 LCI 143, M3 G81 144 + G81 LCI 145, M4 G82 228 + G83 229, M2 G87 216, X4M F98 233.
-- Engine S58B30 3.0 TT I6: base S58B30B (895) + CS S58B30A (896). Verified on M3 G80 HaynesPro:
-- oil 7.0 L, coolant 11.5 L, Li-ion 70Ah battery, full-LED. Filter 11428583898, NGK 12120040551.

-- ---- DEDUP: remove generic S58B30 (236) rows from M3 G80/G81 (kept specific 895/896) ----
DELETE FROM spec_sources WHERE spec_table='fluid_specs' AND spec_id IN (1996,1997,1998,1999,2000,2001,2002,2003);
DELETE FROM fluid_specs WHERE id IN (1996,1997,1998,1999,2000,2001,2002,2003);

-- ---- fill the NULL S58 coolant capacities (895/896 rows) ----
UPDATE fluid_specs SET capacity_l=11.50, capacity_qt=ROUND(11.50*1.05669,2)
  WHERE fluid_type='coolant' AND capacity_l IS NULL AND engine_id IN (895,896)
    AND generation_id IN (142,143,144,145,216,228,229,233);

-- ---- ELECTRICAL: Li-ion 12V for M3 G80/G81 (others already have battery) ----
INSERT INTO electrical_specs (generation_id, battery_group, ah, cca, alternator_amps) VALUES
  (142,'Li-ion',70,720,250),(143,'Li-ion',70,720,250),(144,'Li-ion',70,720,250),(145,'Li-ion',70,720,250);

-- ---- FLUIDS: common adds (all 8) + per-gen specials ----
INSERT INTO fluid_specs (generation_id, engine_id, fluid_type, capacity_l, viscosity, spec_standard, notes)
SELECT g,NULL,'differential_rear',1.00,NULL,'BMW M Active differential oil',NULL FROM (SELECT 142 g UNION SELECT 143 UNION SELECT 144 UNION SELECT 145 UNION SELECT 216 UNION SELECT 228 UNION SELECT 229 UNION SELECT 233) x
UNION ALL SELECT g,NULL,'ac_refrigerant',NULL,NULL,'R1234yf','Charge per under-hood label' FROM (SELECT 142 g UNION SELECT 143 UNION SELECT 144 UNION SELECT 145 UNION SELECT 216 UNION SELECT 228 UNION SELECT 229 UNION SELECT 233) x
UNION ALL SELECT g,NULL,'washer_fluid',NULL,NULL,NULL,'Universal washer fluid; winter mix below 0 C.' FROM (SELECT 142 g UNION SELECT 143 UNION SELECT 144 UNION SELECT 145 UNION SELECT 216 UNION SELECT 228 UNION SELECT 229 UNION SELECT 233) x;
-- M2 G87: + 8-speed M Steptronic auto; X4M F98 (AWD): + front differential
INSERT INTO fluid_specs (generation_id, engine_id, fluid_type, capacity_l, viscosity, spec_standard, notes) VALUES
  (216,NULL,'transmission_at',NULL,NULL,'ZF 8HP','8-speed M Steptronic (where fitted)'),
  (233,NULL,'differential_front',0.60,NULL,'BMW axle oil','xDrive front axle');

