-- ---- CITATIONS (per-gen source) ----
INSERT IGNORE INTO spec_sources (spec_table, spec_id, source_id)
SELECT tbl, id, CASE generation_id WHEN 216 THEN 933 WHEN 228 THEN 907 WHEN 229 THEN 913 WHEN 233 THEN 917 ELSE 910 END
FROM (
  SELECT 'fluid_specs' tbl, id, generation_id FROM fluid_specs WHERE generation_id IN (142,143,144,145,216,228,229,233)
  UNION ALL SELECT 'electrical_specs', id, generation_id FROM electrical_specs WHERE generation_id IN (142,143,144,145)
  UNION ALL SELECT 'tire_pressures', id, generation_id FROM tire_pressures WHERE generation_id IN (143,144,145,229)
  UNION ALL SELECT 'bulbs', id, generation_id FROM bulbs WHERE generation_id IN (142,143,144,145,216,228,229,233)
  UNION ALL SELECT 'fuses', id, generation_id FROM fuses WHERE generation_id IN (142,143,144,145,216,228,229,233)
  UNION ALL SELECT 'service_intervals', id, generation_id FROM service_intervals WHERE generation_id IN (142,143,144,145,216,228,229,233)
  UNION ALL SELECT 'parts', id, generation_id FROM parts WHERE generation_id IN (142,143,144,145,216,228,229,233)
) z;
